import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { 
  adminGetAllUsers, adminDeleteTargetUser, getUserData, adminUpdateUserData,
  adminAddProduct, adminUpdateProduct, adminDeleteProduct 
} from '../utils/api';

function AdminPanel({ user }) {
  const [activeTab, setActiveTab] = useState("users"); // Switcher options: "users" or "products"
  const [users, setUsers] = useState([]);
  const [selectedUser, setSelectedUser] = useState(null);
  const [editRole, setEditRole] = useState("");

  // Product Form Management States
  const [pName, setPName] = useState("");
  const [pPrice, setPPrice] = useState("");
  const [pDesc, setPDesc] = useState("");
  const [pStock, setPStock] = useState("");
  const [editingProductId, setEditingProductId] = useState(null);

  const navigate = useNavigate();

  useEffect(() => {
    if (!user || user.role !== "admin") {
      navigate("/login");
    } else {
      refreshUserList();
    }
  }, [user, navigate]);

  function refreshUserList() {
    adminGetAllUsers().then(data => setUsers(data)).catch(err => console.error(err));
  }

  if (!user || user.role !== "admin") return null;

  // Modify User Assignment
  function handleSaveUserChanges(username) {
    adminUpdateUserData(username, { role: editRole })
      .then(res => {
        if (res.success) {
          alert("User role updated successfully!");
          refreshUserList();
          setSelectedUser(null);
        }
      });
  }

  // Handle Adding or Patching Products
  function handleProductSubmit(e) {
    e.preventDefault();
    const payload = { name: pName, price: pPrice, description: pDesc, stock: pStock };

    if (editingProductId) {
      adminUpdateProduct(editingProductId, payload).then(res => {
        if (res.success) {
          alert("Product properties adjusted!");
          resetProductForm();
        }
      });
    } else {
      adminAddProduct(payload).then(res => {
        if (res.success) {
          alert("Product injected to sales catalog system!");
          resetProductForm();
        }
      });
    }
  }

  function resetProductForm() {
    setPName(""); setPPrice(""); setPDesc(""); setPStock("");
    setEditingProductId(null);
  }

  return (
    <div style={{ padding: "30px", maxWidth: "1100px", margin: "auto" }}>
      <h2>System Administrator Command Center Workspace</h2>
      
      {/* Workspace Navigator Buttons Layout */}
      <div style={{ marginBottom: "20px" }}>
        <button onClick={() => setActiveTab("users")} style={{ padding: "10px 20px", marginRight: "10px", background: activeTab === "users" ? "#007bff" : "#6c757d", color: "#fff", border: "none", borderRadius: "4px" }}>Manage User Accounts</button>
        <button onClick={() => setActiveTab("products")} style={{ padding: "10px 20px", background: activeTab === "products" ? "#28a745" : "#6c757d", color: "#fff", border: "none", borderRadius: "4px" }}>Product Inventory Editor</button>
      </div>

      {activeTab === "users" ? (
        <div>
          <h3>User Profiles Management Datatable</h3>
          <table style={{ width: "100%", borderCollapse: "collapse" }}>
            <thead>
              <tr style={{ background: "#343a40", color: "#fff" }}>
                <th style={{ padding: "10px", border: "1px solid #ddd" }}>Username</th>
                <th style={{ padding: "10px", border: "1px solid #ddd" }}>Email</th>
                <th style={{ padding: "10px", border: "1px solid #ddd" }}>Current Role</th>
                <th style={{ padding: "10px", border: "1px solid #ddd" }}>Actions</th>
              </tr>
            </thead>
            <tbody>
              {users.map(u => (
                <tr key={u.username}>
                  <td style={{ padding: "10px", border: "1px solid #ddd" }}>{u.username}</td>
                  <td style={{ padding: "10px", border: "1px solid #ddd" }}>{u.email}</td>
                  <td style={{ padding: "10px", border: "1px solid #ddd" }}><strong>{u.role}</strong></td>
                  <td style={{ padding: "10px", border: "1px solid #ddd" }}>
                    <button onClick={() => { setSelectedUser(u); setEditRole(u.role); }} style={{ marginRight: "5px", background: "#17a2b8", color: "#fff", border: "none", padding: "5px 10px", borderRadius: "4px" }}>Edit / Inspect</button>
                    <button onClick={() => { if(window.confirm("Drop account item profile?")) adminDeleteTargetUser(u.username).then(() => refreshUserList()); }} style={{ background: "#dc3545", color: "#fff", border: "none", padding: "5px 10px", borderRadius: "4px" }}>Delete</button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>

          {selectedUser && (
            <div style={{ marginTop: "20px", border: "1px solid #007bff", padding: "20px", borderRadius: "8px" }}>
              <h4>Modify Account Context: {selectedUser.username}</h4>
              <label style={{ display: "block", marginBottom: "10px" }}>
                Adjust Authority Tier Role Level Selection:
                <select value={editRole} onChange={e => setEditRole(e.target.value)} style={{ marginLeft: "10px", padding: "5px" }}>
                  <option value="user">User (Standard Access)</option>
                  <option value="admin">Admin (Master Credentials)</option>
                </select>
              </label>
              <button onClick={() => handleSaveUserChanges(selectedUser.username)} style={{ background: "#28a745", color: "#fff", padding: "5px 15px", border: "none", borderRadius: "4px", marginRight: "5px" }}>Save Settings Changes</button>
              <button onClick={() => setSelectedUser(null)} style={{ background: "#6c757d", color: "#fff", padding: "5px 15px", border: "none", borderRadius: "4px" }}>Cancel</button>
            </div>
          )}
        </div>
      ) : (
        <div>
          <h3>{editingProductId ? "🔄 Edit Store Item" : "➕ Append New Product to Catalog"}</h3>
          <form onSubmit={handleProductSubmit} style={{ background: "#f8f9fa", padding: "20px", borderRadius: "8px", marginBottom: "30px" }}>
            <input type="text" placeholder="Product Title / Name" value={pName} onChange={e => setPName(e.target.value)} style={{ display: "block", width: "100%", marginBottom: "10px", padding: "8px" }} required />
            <input type="number" placeholder="Sales Retail Price ($)" value={pPrice} onChange={e => setPPrice(e.target.value)} style={{ display: "block", width: "100%", marginBottom: "10px", padding: "8px" }} required />
            <input type="number" placeholder="Available Warehouse Stock Units" value={pStock} onChange={e => setPStock(e.target.value)} style={{ display: "block", width: "100%", marginBottom: "10px", padding: "8px" }} required />
            <textarea placeholder="Product Description Context Summary" value={pDesc} onChange={e => setPDesc(e.target.value)} style={{ display: "block", width: "100%", marginBottom: "10px", padding: "8px", minHeight: "8px" }} />
            
            <button type="submit" style={{ background: "#28a745", color: "#fff", padding: "10px 20px", border: "none", borderRadius: "4px", marginRight: "10px" }}>{editingProductId ? "Commit System Updates" : "Publish Global Live Product Item"}</button>
            {editingProductId && <button type="button" onClick={resetProductForm} style={{ background: "#6c757d", color: "#fff", padding: "10px 20px", border: "none", borderRadius: "4px" }}>Exit Edit State</button>}
          </form>
        </div>
      )}
    </div>
  );
}

export default AdminPanel;
